def pipeline(edad_s: str, monto_s: str) -> dict:
    raw = {"edad": edad_s, "monto": monto_s}
    clean = {"edad": None, "monto": None}
    errors = []
    ok, n, err = safe_int("edad", edad_s)
    if ok:
        clean["edad"] = n
    else:
        errors.append(err)
    ok2, m, err2 = safe_float("monto", monto_s)
    if ok2:
        clean["monto"] = m
    else:
        errors.append(err2)
    return {"raw": raw, "clean": clean, "errors": errors}

print(pipeline(" 21 ", "10.5"))
print(pipeline("abc", "10.5"))
print(pipeline("21", "xyz"))

